/**
 * SEO Hooks for VNVT Store
 * Feature #85: SEO Head Management (title, meta, OG, Twitter Card)
 * Feature #86: Canonical Tag Management
 * Feature #87: Schema.org JSON-LD (Product, Organization, Breadcrumb)
 * 
 * All self-contained, no third-party dependencies.
 */
import { useEffect } from 'react';

const SITE_NAME = 'VNVT Store';
const DEFAULT_OG_IMAGE = '/og-image.png';
const SITE_URL = typeof window !== 'undefined' ? window.location.origin : 'https://vnvtstore.com';

// ============ Helper: Set/Remove Meta Tags ============
const setMetaTag = (property: string, content: string, isProperty = false) => {
    const attr = isProperty ? 'property' : 'name';
    let el = document.querySelector(`meta[${attr}="${property}"]`) as HTMLMetaElement;
    if (!el) {
        el = document.createElement('meta');
        el.setAttribute(attr, property);
        document.head.appendChild(el);
    }
    el.content = content;
    return el;
};

const removeMetaTag = (property: string, isProperty = false) => {
    const attr = isProperty ? 'property' : 'name';
    const el = document.querySelector(`meta[${attr}="${property}"]`);
    if (el) el.remove();
};

// ============ #86 Canonical Tag ============
export const useCanonical = (path?: string) => {
    useEffect(() => {
        const url = path
            ? `${window.location.origin}${path}`
            : window.location.href.split('?')[0];

        let link = document.querySelector('link[rel="canonical"]') as HTMLLinkElement;
        if (!link) {
            link = document.createElement('link');
            link.rel = 'canonical';
            document.head.appendChild(link);
        }
        link.href = url;

        return () => {
            if (link.parentNode) link.parentNode.removeChild(link);
        };
    }, [path]);
};

// ============ #87 Schema.org JSON-LD ============
interface ProductSchemaProps {
    name: string;
    description?: string;
    imageUrl?: string;
    price?: number;
    currency?: string;
    brand?: string;
    sku?: string;
    rating?: number;
    reviewCount?: number;
    availability?: 'InStock' | 'OutOfStock' | 'PreOrder';
}

export const useProductSchema = (product: ProductSchemaProps | null) => {
    useEffect(() => {
        if (!product) return;

        const schema: Record<string, unknown> = {
            '@context': 'https://schema.org',
            '@type': 'Product',
            name: product.name,
            description: product.description || '',
            image: product.imageUrl || '',
            sku: product.sku || '',
            brand: product.brand ? {
                '@type': 'Brand',
                name: product.brand,
            } : undefined,
            offers: {
                '@type': 'Offer',
                price: product.price || 0,
                priceCurrency: product.currency || 'VND',
                availability: `https://schema.org/${product.availability || 'InStock'}`,
                url: window.location.href,
            },
        };

        if (product.rating && product.reviewCount) {
            schema.aggregateRating = {
                '@type': 'AggregateRating',
                ratingValue: product.rating,
                reviewCount: product.reviewCount,
                bestRating: 5,
            };
        }

        const script = document.createElement('script');
        script.type = 'application/ld+json';
        script.textContent = JSON.stringify(schema);
        script.id = 'product-jsonld';

        // Remove old one if exists
        const old = document.getElementById('product-jsonld');
        if (old) old.remove();

        document.head.appendChild(script);

        return () => {
            const el = document.getElementById('product-jsonld');
            if (el) el.remove();
        };
    }, [product]);
};

// ============ Organization Schema ============
export const useOrganizationSchema = () => {
    useEffect(() => {
        const schema = {
            '@context': 'https://schema.org',
            '@type': 'Organization',
            name: 'VNVT Store',
            url: SITE_URL,
            logo: `${SITE_URL}/vite.svg`,
            description: 'Hệ thống cửa hàng đồ gia dụng cao cấp, chính hãng. Miễn phí vận chuyển toàn quốc.',
            contactPoint: {
                '@type': 'ContactPoint',
                contactType: 'customer service',
                availableLanguage: 'Vietnamese',
            },
            sameAs: [],
        };

        const script = document.createElement('script');
        script.type = 'application/ld+json';
        script.textContent = JSON.stringify(schema);
        script.id = 'org-jsonld';

        const old = document.getElementById('org-jsonld');
        if (old) old.remove();

        document.head.appendChild(script);

        return () => {
            const el = document.getElementById('org-jsonld');
            if (el) el.remove();
        };
    }, []);
};

// ============ Breadcrumb Schema ============
interface BreadcrumbItem {
    name: string;
    url: string;
}

export const useBreadcrumbSchema = (items: BreadcrumbItem[]) => {
    useEffect(() => {
        if (!items.length) return;

        const schema = {
            '@context': 'https://schema.org',
            '@type': 'BreadcrumbList',
            itemListElement: items.map((item, i) => ({
                '@type': 'ListItem',
                position: i + 1,
                name: item.name,
                item: item.url.startsWith('http') ? item.url : `${SITE_URL}${item.url}`,
            })),
        };

        const script = document.createElement('script');
        script.type = 'application/ld+json';
        script.textContent = JSON.stringify(schema);
        script.id = 'breadcrumb-jsonld';

        const old = document.getElementById('breadcrumb-jsonld');
        if (old) old.remove();

        document.head.appendChild(script);

        return () => {
            const el = document.getElementById('breadcrumb-jsonld');
            if (el) el.remove();
        };
    }, [items]);
};

// ============ #85 SEO Head Management (Enhanced) ============
interface SEOProps {
    title: string;
    description?: string;
    canonicalPath?: string;
    ogImage?: string;
    ogType?: 'website' | 'article' | 'product';
    noindex?: boolean;
    keywords?: string;
}

export const useSEO = ({
    title,
    description,
    canonicalPath,
    ogImage,
    ogType = 'website',
    noindex = false,
    keywords,
}: SEOProps) => {
    useEffect(() => {
        const prevTitle = document.title;
        const fullTitle = `${title} | ${SITE_NAME}`;
        document.title = fullTitle;

        const currentUrl = canonicalPath
            ? `${SITE_URL}${canonicalPath}`
            : window.location.href.split('?')[0];

        // Meta description
        if (description) {
            setMetaTag('description', description);
        }

        // Keywords
        if (keywords) {
            setMetaTag('keywords', keywords);
        }

        // Robots
        if (noindex) {
            setMetaTag('robots', 'noindex, nofollow');
        } else {
            setMetaTag('robots', 'index, follow');
        }

        // Open Graph
        setMetaTag('og:title', fullTitle, true);
        setMetaTag('og:type', ogType, true);
        setMetaTag('og:url', currentUrl, true);
        setMetaTag('og:site_name', SITE_NAME, true);
        if (description) setMetaTag('og:description', description, true);
        if (ogImage || DEFAULT_OG_IMAGE) {
            const imgUrl = ogImage?.startsWith('http') ? ogImage : `${SITE_URL}${ogImage || DEFAULT_OG_IMAGE}`;
            setMetaTag('og:image', imgUrl, true);
        }

        // Twitter Card
        setMetaTag('twitter:card', ogImage ? 'summary_large_image' : 'summary');
        setMetaTag('twitter:title', fullTitle);
        setMetaTag('twitter:description', description || '');
        if (ogImage || DEFAULT_OG_IMAGE) {
            const imgUrl = ogImage?.startsWith('http') ? ogImage : `${SITE_URL}${ogImage || DEFAULT_OG_IMAGE}`;
            setMetaTag('twitter:image', imgUrl);
        }

        return () => {
            document.title = prevTitle;
            // Note: don't remove OG/Twitter tags on cleanup since index.html has defaults
        };
    }, [title, description, ogImage, ogType, noindex, keywords, canonicalPath]);

    useCanonical(canonicalPath);
};

import { useEffect } from 'react';
import { useCartStore, useUIStore } from '@/store';
import { Outlet } from 'react-router-dom';
import { Header } from '@/components/layout/Header';
import { Footer } from '@/components/layout/Footer';
import { QuickViewModal } from '@/components/common';
import { CartDrawer } from '@/components/common/CartDrawer';
import { ChatWidget } from '@/components/common/ChatWidget';
import { AnnouncementBanner } from '@/components/common/AnnouncementBanner';
import { FloatingContact } from '@/components/common/FloatingContact';

export const ShopLayout = () => {
  const { fetchCart } = useCartStore();
  const { quickViewProduct, setQuickViewProduct } = useUIStore();

  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  return (
    <div className="flex flex-col min-h-screen">
      <AnnouncementBanner />
      <Header />
      <main className="flex-1">
        <Outlet />
      </main>
      <Footer />
      <CartDrawer />
      <FloatingContact />
      <QuickViewModal
        product={quickViewProduct}
        isOpen={!!quickViewProduct}
        onClose={() => setQuickViewProduct(null)}
      />
    </div>
  );
};

export default ShopLayout;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Star, Check, X, MessageSquare, Trash2, Search } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';
import { AdminPageHeader } from '@/components/admin';
import { DataTable } from '@/components/common';
import { formatDate } from '@/utils/format';
import { reviewService, type ReviewDto } from '@/services/reviewService';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { PaginationDefaults } from '@/constants';
import { useToast } from '@/store';
import { REVIEW_LIST_FIELDS } from '@/constants/fieldConstants';

export const ReviewsPage = () => {
  const { t } = useTranslation();
  const { success, error: toastError } = useToast();
  const queryClient = useQueryClient();

  // State
  const [currentPage, setCurrentPage] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedReview, setSelectedReview] = useState<ReviewDto | null>(null);
  const [reviewToDelete, setReviewToDelete] = useState<ReviewDto | null>(null);
  const [replyText, setReplyText] = useState('');

  // Queries
  const { data: reviewsData, isLoading, isFetching } = useQuery({
    queryKey: ['admin-reviews', currentPage, pageSize, searchQuery],
    queryFn: () => reviewService.search({
      pageIndex: currentPage,
      pageSize: pageSize,
      search: searchQuery,
      fields: REVIEW_LIST_FIELDS
    }),
  });

  const reviews = reviewsData?.data?.items || [];
  const totalPages = reviewsData?.data?.totalPages || 1;

  // Mutations
  const deleteMutation = useMutation({
    mutationFn: (code: string) => reviewService.delete(code),
    onSuccess: () => {
      success(t('messages.deleteSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-reviews'] });
      setReviewToDelete(null);
    },
    onError: () => toastError(t('messages.deleteError'))
  });

  const replyMutation = useMutation({
    mutationFn: (data: { code: string, reply: string }) => 
      reviewService.reply(data.code, data.reply),
    onSuccess: () => {
      success(t('messages.updateSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-reviews'] });
      setSelectedReview(null);
      setReplyText('');
    },
    onError: () => toastError(t('messages.updateError'))
  });

  // Handlers
  const handleReply = () => {
    if (selectedReview && replyText.trim()) {
      replyMutation.mutate({ code: selectedReview.code, reply: replyText });
    }
  };

  const renderStars = (rating: number) => {
    return (
      <div className="flex gap-0.5">
        {Array.from({ length: 5 }).map((_, i) => (
          <Star
            key={i}
            size={14}
            className={i < rating ? 'fill-yellow-400 text-yellow-400' : 'text-gray-300'}
          />
        ))}
      </div>
    );
  };

  // Columns
  const columns = [
    {
      id: 'product',
      header: t('common.fields.product'),
      accessor: (row: ReviewDto) => (
        <div className="max-w-[200px]">
          <p className="font-medium truncate">{row.productName || row.productCode}</p>
          <p className="text-xs text-tertiary">{row.productCode}</p>
        </div>
      )
    },
    {
      id: 'user',
      header: t('common.fields.user'),
      accessor: (row: ReviewDto) => (
        <div>
          <p className="font-medium">{row.userName}</p>
          <p className="text-xs text-secondary">{row.userCode}</p>
        </div>
      )
    },
    {
      id: 'rating',
      header: t('common.fields.rating'),
      accessor: (row: ReviewDto) => renderStars(row.rating),
      className: 'text-center'
    },
    {
      id: 'comment',
      header: t('common.fields.comment'),
      accessor: (row: ReviewDto) => (
        <div className="max-w-[300px]">
          <p className="text-sm line-clamp-2">{row.comment}</p>
          {row.replies && row.replies.length > 0 && (
            <p className="text-xs text-primary mt-1 flex items-center gap-1 italic">
              <MessageSquare size={10} /> {t('admin.reviews.replied')} ({row.replies.length})
            </p>
          )}
        </div>
      )
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (row: ReviewDto) => (
        <Badge color={row.isApproved ? 'success' : 'warning'} size="sm">
          {row.isApproved ? t('admin.reviews.approved') : t('admin.reviews.pending')}
        </Badge>
      ),
      className: 'text-center'
    },
    {
      id: 'date',
      header: t('common.fields.date'),
      accessor: (row: ReviewDto) => <span className="text-secondary text-sm">{formatDate(row.createdAt)}</span>
    }
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.reviews"
        subtitle="admin.subtitles.reviews"
      />

      <DataTable
        columns={columns}
        data={reviews}
        isLoading={isLoading || isFetching}
        keyField="code"
        
        currentPage={currentPage}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setCurrentPage}
        onPageSizeChange={setPageSize}

        // Standardized Toolbar
        onSearch={setSearchQuery}
        onRefresh={() => queryClient.invalidateQueries({ queryKey: ['admin-reviews'] })}
        
        onReset={() => {
            setSearchQuery('');
            setCurrentPage(PaginationDefaults.PAGE_INDEX);
        }}
        
        renderRowActions={(row) => (
          <div className="flex items-center gap-1">
            <button
              className="p-1.5 hover:bg-primary/10 rounded text-primary"
              title={t('admin.actions.reply')}
              onClick={() => {
                setSelectedReview(row);
                setReplyText('');
              }}
            >
              <MessageSquare size={18} />
            </button>
            <button
              className="p-1.5 hover:bg-error/10 rounded text-error"
              title={t('common.actions.delete')}
              onClick={() => setReviewToDelete(row)}
            >
              <Trash2 size={18} />
            </button>
          </div>
        )}
      />

      {/* Reply Modal */}
      <Modal
        isOpen={!!selectedReview}
        onClose={() => setSelectedReview(null)}
        title={t('admin.reviews.replyTitle')}
        footer={
          <div className="flex justify-end gap-2">
            <Button variant="ghost" onClick={() => setSelectedReview(null)}>{t('common.cancel')}</Button>
            <Button onClick={handleReply} isLoading={replyMutation.isPending}>{t('common.save')}</Button>
          </div>
        }
      >
        {selectedReview && (
          <div className="space-y-4">
            <div className="bg-secondary p-4 rounded-lg">
              <div className="flex justify-between items-start mb-2">
                <span className="font-bold">{selectedReview.userName}</span>
                {renderStars(selectedReview.rating)}
              </div>
              <p className="text-sm text-secondary italic">&quot;{selectedReview.comment}&quot;</p>
            </div>
            {selectedReview.replies && selectedReview.replies.length > 0 && (
              <div className="space-y-2 max-h-40 overflow-y-auto pr-2">
                <p className="text-xs font-bold text-tertiary uppercase">{t('admin.reviews.existingReplies') || 'Existing Replies'}</p>
                {selectedReview.replies.map((reply, idx) => (
                  <div key={reply.code || idx} className="bg-tertiary/10 p-2 rounded text-sm border-l-2 border-indigo-500">
                    <p className="text-xs font-semibold">{reply.userName || 'Admin'}</p>
                    <p>{reply.comment}</p>
                  </div>
                ))}
              </div>
            )}
            <div>
              <label className="block text-sm font-medium mb-1">{t('admin.reviews.yourReply')}</label>
              <textarea
                className="w-full p-3 bg-primary border rounded-lg h-32 focus:ring-2 focus:ring-primary/20 outline-none"
                placeholder={t('admin.reviews.replyPlaceholder')}
                value={replyText}
                onChange={(e) => setReplyText(e.target.value)}
              />
            </div>
          </div>
        )}
      </Modal>

      <ConfirmDialog
        isOpen={!!reviewToDelete}
        onClose={() => setReviewToDelete(null)}
        onConfirm={() => reviewToDelete && deleteMutation.mutate(reviewToDelete.code)}
        title={t('common.actions.delete')}
        message={t('messages.confirmDelete')}
        variant="danger"
        isLoading={deleteMutation.isPending}
      />
    </div>
  );
};

export default ReviewsPage;

